import React from 'react';
import { Container, Row, Col } from 'react-bootstrap';
import Fb from "../images/Social/facebook.png"
import Dis from "../images/Social/Discord.png"
import Mail from "../images/Social/Gmail.png"

function Footer() {
    return(
        <div style={{backgroundColor: "darkgrey"}}>
            <Container className="lg-container">
                <Row>
                    <Col xs={4} className='d-flex justify-content-center p-5'>Fardin Mridul</Col>
                    <Col xs={4} className='d-flex justify-content-center p-5'>
                        <a href="https://www.facebook.com/"><img style={{height: "40px", width: "40px" }}  src={Fb} alt="facebook" /></a>
                        <a href="https://www.facebook.com/"><img style={{height: "40px", width: "40px" }} className='ml-4 mr-4' src={Mail} alt="facebook" /></a>
                        <a href="https://www.facebook.com/"><img style={{height: "40px", width: "40px" }}  src={Dis} alt="facebook" /></a>
                    </Col>
                    <Col xs={4} className='d-flex justify-content-center p-5'>New Text</Col>
                </Row>
            </Container>
        </div>
    )
}

export default Footer