import React from "react";
import { Container, Row, Col } from "reactstrap";
import { SectionXNeg, SectionYNeg, StaggeredText } from "./Animations";
import MediaQuery from "react-responsive";
import dem from "../images/demo.mp4"
 
function AboutMe () {
    return (
        <Container className="lg-container">
            <h2 className="headerdec mt-5 mb-5"><StaggeredText text={"About Me"}></StaggeredText></h2>
            <Row>
                <Col md={6}>
                    <div className="embed-responsive embed-responsive-16by9">
                        <video className="embed-responsive-item" controls style={{ borderRadius: '15px' }}>
                            <source src={dem} type="video/mp4" />
                            Your browser does not support the video tag.
                        </video>
                    </div>
                </Col>
                <Col md={6} className="d-flex align-items-center headertext">
                    <MediaQuery maxWidth={1368}>
                        <SectionYNeg>
                            <div>
                                <h5>Description</h5>
                            </div>
                        </SectionYNeg>
                    </MediaQuery>
                    <MediaQuery minWidth={1368}>
                        <SectionXNeg>
                            <div>
                                <h5>Description</h5>
                            </div>
                        </SectionXNeg>
                    </MediaQuery>
                </Col>
            </Row>
        </Container>
    )
}

export default AboutMe;