import React from 'react';
import {
  Collapse,
  Navbar,
  NavLink,
  NavbarBrand,
  Nav,
  NavItem,
  Container} from 'reactstrap';
import Burger from './Burger';
import MediaQuery from 'react-responsive';

export default class Example extends React.Component {
  constructor(props) {
    super(props);

    this.state = {
      isOpen: false
    };
  }

  render() {
    return (
      <Container className='nav-container'>
        <div className='nav-c'>
        <MediaQuery maxWidth={1368}>
          <Burger/>
        </MediaQuery>
          <Navbar light expand="md">
            <NavbarBrand href="/" className='text-white'>Fardin Mridul</NavbarBrand>
            <Collapse isOpen={this.state.isOpen} navbar>
            <Nav className="ml-auto" navbar>
                <NavItem>
                  <NavLink href="/" className='text-white mt-1'>CV</NavLink>
                </NavItem>
                <NavItem>
                  <NavLink href="/" className='text-white mt-1'>Case Studies</NavLink>
                </NavItem>
                <NavItem>
                  <NavLink href="/" className='text-white mt-1'>Learn</NavLink>
                </NavItem>
              </Nav>
            </Collapse>
          </Navbar>
        </div>
      </Container>
    );
  }
}