import React from "react";
import { Container, Row, Col, Button } from 'reactstrap';
import { SectionYPos } from "./Animations";
import MediaQuery from "react-responsive";
import Arrow from "../images/arrow.gif"

const HeroSec = () => {

    return(
        <>
          <div style={{height: "100vh", backgroundColor: "black"}}>
            <SectionYPos>
                <div className="jumbotron">
                    <Container className="lg-container">
                        <Row className="mt-4">
                            <Col className="d-flex justify-content-center align-items-center">
                                <div>
                                    <p>Hello, My name is...</p>
                                    <h1>Fardin Rahman</h1>
                                    <h4>Making complex things simplified has always been.</h4>
                                    <Button className="butt mt-5">Reach_Out</Button>
                                    <MediaQuery maxWidth={1368}>
                                        <div style={{marginLeft: "255px", marginTop: "260px"}}>Scroll!!!<img style={{width: "60px"}} src={Arrow} alt="arrow"/> </div>
                                    </MediaQuery>
                                    <MediaQuery minWidth={1368}>
                                        <div style={{marginLeft: "515px", marginTop: "320px"}}>Scroll!!!<img style={{width: "80px"}} src={Arrow} alt="arrow"/> </div>
                                    </MediaQuery>
                                </div>                 
                            </Col>
                        </Row>
{/*                         <Row className="mt-3">
                            <Col>
                                <Button className="butt">Who am I</Button> 
                            </Col>
                        </Row> */}
                    </Container>
                </div>
            </SectionYPos>
          </div>
        </>
    );
}

export default HeroSec;